interface Utilisateur {
  id: number;
  nom: string;
  email: string;
  age?: number; // optionnel
}

// L'objet respecte l'interface
const alice: Utilisateur = {
  id: 1,
  nom: 'Alice',
  email: 'alice@exemple.fr'
};

// Extension d'interface
interface Admin extends Utilisateur {
  permissions: string[];
}

const admin: Admin = {
  id: 2,
  nom: 'Bob',
  email: 'bob@exemple.fr',
  permissions: ['lire', 'écrire', 'supprimer']
};
